// Transform n8n workflows API response → Musa Hub BackstageResponse
const raw = $input.first().json;
const workflows = Array.isArray(raw.data) ? raw.data : (Array.isArray(raw) ? raw : []);

const INTEGRATION_MAP = {
  telegram: 'Telegram',
  telegramTrigger: 'Telegram',
  openAi: 'OpenAI',
  openAiChat: 'OpenAI',
  supabase: 'Supabase',
  postgres: 'Postgres',
  gmail: 'Gmail',
  googleSheets: 'Google Sheets',
  googleCalendar: 'Google Calendar',
  googleDrive: 'Google Drive',
  brevo: 'Brevo',
  sendInBlue: 'Brevo',
  emailSend: 'SMTP',
  slack: 'Slack',
  notion: 'Notion',
  airtable: 'Airtable',
  hubspot: 'HubSpot',
  whatsApp: 'WhatsApp',
  httpRequest: 'HTTP',
  webhook: 'Webhook',
  zadarma: 'Zadarma',
};

const TRIGGER_MAP = {
  webhook: 'webhook',
  telegramTrigger: 'telegram',
  scheduleTrigger: 'schedule',
  cron: 'schedule',
  emailReadImap: 'email',
  gmailTrigger: 'email',
  manualTrigger: 'manual',
  formTrigger: 'form',
  executeWorkflowTrigger: 'subflow',
  errorTrigger: 'error',
};

function shortType(t) {
  if (!t) return '';
  return String(t).split('.').pop().replace(/Trigger$/, 'Trigger');
}

function prettyIntegration(t) {
  const s = shortType(t).replace(/Trigger$/, '');
  if (INTEGRATION_MAP[s]) return INTEGRATION_MAP[s];
  // skip core flow-control nodes
  const skip = new Set(['set','if','switch','merge','splitInBatches','code','function','noOp','stickyNote','wait','respondToWebhook','executeWorkflow','aggregate','itemLists','dateTime','filter']);
  if (skip.has(s)) return null;
  // Title-case fallback
  return s.charAt(0).toUpperCase() + s.slice(1).replace(/([A-Z])/g, ' $1').trim();
}

function detectTrigger(t) {
  const s = shortType(t);
  return TRIGGER_MAP[s] || null;
}

const out = workflows.map((wf) => {
  const nodes = Array.isArray(wf.nodes) ? wf.nodes : [];
  const connections = wf.connections || {};

  // triggers
  const triggers = Array.from(new Set(
    nodes.map((n) => detectTrigger(n.type)).filter(Boolean)
  ));

  // integrations
  const integrations = Array.from(new Set(
    nodes.map((n) => prettyIntegration(n.type)).filter(Boolean)
  ));

  // endpoints (webhook nodes)
  const endpoints = nodes
    .filter((n) => shortType(n.type) === 'webhook')
    .map((n) => ({
      path: '/webhook/' + (n.parameters?.path || ''),
      method: (n.parameters?.httpMethod || 'GET').toUpperCase(),
    }));

  // schedule (first scheduleTrigger / cron expression)
  let schedule;
  const sched = nodes.find((n) => ['scheduleTrigger','cron'].includes(shortType(n.type)));
  if (sched) {
    const rules = sched.parameters?.rule?.interval || sched.parameters?.triggerTimes?.item;
    if (Array.isArray(rules) && rules.length) {
      const r = rules[0];
      schedule = r.cronExpression || r.expression || JSON.stringify(r);
    } else {
      schedule = 'configurado en n8n';
    }
  }

  // description (first sticky note or workflow meta)
  let description = wf.meta?.description || '';
  if (!description) {
    const sticky = nodes.find((n) => shortType(n.type) === 'stickyNote' && n.parameters?.content);
    if (sticky) {
      description = String(sticky.parameters.content)
        .replace(/^#+\s*/gm, '')
        .split('\n')
        .map((l) => l.trim())
        .filter(Boolean)[0] || '';
    }
  }

  // graph
  const graphNodes = nodes
    .filter((n) => shortType(n.type) !== 'stickyNote')
    .map((n) => ({ id: String(n.id || n.name), label: n.name }));

  const idByName = {};
  nodes.forEach((n) => { idByName[n.name] = String(n.id || n.name); });

  const edges = [];
  Object.entries(connections).forEach(([fromName, outs]) => {
    const mainOuts = (outs && outs.main) || [];
    mainOuts.forEach((arr) => {
      (arr || []).forEach((conn) => {
        if (!conn || !conn.node) return;
        const from = idByName[fromName];
        const to = idByName[conn.node];
        if (from && to) edges.push({ from, to });
      });
    });
  });

  return {
    id: String(wf.id),
    name: wf.name,
    active: !!wf.active,
    triggers,
    schedule,
    endpoints: endpoints.length ? endpoints : undefined,
    integrations,
    tags: Array.isArray(wf.tags) ? wf.tags.map((t) => t.name || t).filter(Boolean) : [],
    description,
    graph: { nodes: graphNodes, edges },
  };
});

return [{
  json: {
    generated_at: new Date().toISOString(),
    total_workflows: out.length,
    workflows: out,
  },
}];
